def heuristic_options_fill_deficit(fill_rate_data: dict) -> tuple[bool, str]:
    """Flag chronic under-fill on options-momentum — limit prices likely too tight."""
    opts = fill_rate_data.get("options-momentum", {})
    placed = opts.get("placed", 0)
    fill_rate = opts.get("fill_rate", 1.0)
    if placed >= 5 and fill_rate < 0.50:
        missed = round((1 - fill_rate) * placed)
        return True, (
            f"options-momentum fill_rate={fill_rate:.0%} on {placed} orders "
            f"— ~{missed} intended positions missed; limit prices too tight"
        )
    return False, ""

