class TestOptionsFillDeficit(unittest.TestCase):
    def test_triggers_low_fill_sufficient_sample(self):
        data = {"options-momentum": {"placed": 10, "fill_rate": 0.4}}
        fired, reason = heuristic_options_fill_deficit(data)
        self.assertTrue(fired)
        self.assertIn("fill_rate=40%", reason)
        self.assertIn("6 intended positions missed", reason)

    def test_no_trigger_insufficient_sample(self):
        data = {"options-momentum": {"placed": 3, "fill_rate": 0.2}}
        fired, _ = heuristic_options_fill_deficit(data)
        self.assertFalse(fired)

    def test_no_trigger_acceptable_fill(self):
        data = {"options-momentum": {"placed": 10, "fill_rate": 0.7}}
        fired, _ = heuristic_options_fill_deficit(data)
        self.assertFalse(fired)

    def test_no_trigger_missing_key(self):
        fired, _ = heuristic_options_fill_deficit({})
        self.assertFalse(fired)

    def test_boundary_exactly_50pct(self):
        data = {"options-momentum": {"placed": 10, "fill_rate": 0.50}}
        fired, _ = heuristic_options_fill_deficit(data)
        self.assertFalse(fired)
